// BIH-relevant keywords — priority keywords (higher signal, more specific)
const PRIORITY_KW = [
  'excavator attachment', 'bucket attachment', 'hydraulic thumb',
  'ripper attachment', 'earth auger', 'quick coupler', 'quick hitch',
  'hydraulic breaker', 'hydraulic hammer', 'skeleton bucket',
  'compaction wheel', 'tilt coupler', 'demolition attachment'
];

const GENERAL_KW = [
  'excavator', 'attachment', 'bucket', 'thumb', 'ripper', 'auger',
  'coupler', 'breaker', 'grapple', 'compactor', 'grading',
  'earthwork', 'trenching', 'heavy equipment', 'construction equipment',
  'dozer blade', 'plate compactor'
];

const REGION_MAP = {
  ontario:     'Ontario',
  toronto:     'Toronto',
  'greater toronto': 'GTA',
  gta:         'GTA',
  durham:      'Durham Region',
  york:        'York Region',
  peel:        'Peel Region',
  halton:      'Halton',
  brampton:    'Brampton',
  mississauga: 'Mississauga',
  markham:     'Markham',
  oakville:    'Oakville',
  hamilton:    'Hamilton',
  vaughan:     'Vaughan',
  barrie:      'Barrie',
  kingston:    'Kingston',
  ottawa:      'Ottawa',
  kanata:      'Ottawa',
  london:      'London ON'
};

const results = [];
const seenIds = new Set();

for (const item of $input.all()) {
  const d = item.json;
  if (!d || typeof d !== 'object') continue;

  const text = `${d.title || ''} ${d.content || d.contentSnippet || d.description || ''}`.toLowerCase();
  if (text.trim().length === 0) continue;

  // Keyword matching — priority keywords first, then general
  const priorityHits = PRIORITY_KW.filter(k => text.includes(k));
  const generalHits = GENERAL_KW.filter(k => text.includes(k));
  const kw_hit = [...new Set([...priorityHits, ...generalHits])];
  if (kw_hit.length === 0) continue;

  // Region detection — first match wins (more specific first via REGION_MAP order)
  let region = 'Canada';
  for (const [key, label] of Object.entries(REGION_MAP)) {
    if (text.includes(key)) { region = label; break; }
  }

  // Stable listing ID from GUID, falling back to URL hash
  const rawId = String(d.guid || d.link || d.id || '');
  if (!rawId) continue;
  const listing_id = 'CB-' + rawId.replace(/[^a-zA-Z0-9]/g, '').slice(-60);
  if (listing_id === 'CB-') continue;
  if (seenIds.has(listing_id)) continue;
  seenIds.add(listing_id);

  // Try to extract closing/deadline date from content
  const closingMatch = text.match(/clos(?:ing|es?)[^\d]{0,20}(\d{4}-\d{2}-\d{2})/) ||
                       text.match(/deadline[^\d]{0,20}(\d{4}-\d{2}-\d{2})/);

  results.push({
    json: {
      listing_id,
      title: (d.title || 'Untitled').trim().slice(0, 500),
      region,
      source_url: (d.link || '').slice(0, 500),
      keywords_hit: kw_hit.slice(0, 20),
      ...(closingMatch ? { deadline: closingMatch[1] } : {})
    }
  });
}

return results;

const tenders = $input.item.json.tenders || [];
if (tenders.length === 0) return [];

const lines = tenders.map((t, i) => {
  const kws = Array.isArray(t.keywords_hit) ? t.keywords_hit.slice(0, 5).join(', ') : '';
  return [
    `*${i + 1}. ${(t.title || '').slice(0, 100)}*`,
    `📍 ${t.region || 'Canada'}` + (t.deadline ? `  ⏰ 截止 ${t.deadline}` : ''),
    kws ? `🏷 ${kws}` : '',
    t.source_url ? `🔗 [查看标书](${t.source_url})` : ''
  ].filter(Boolean).join('\n');
}).join('\n\n───\n\n');

const msg = `🚨 *BIH GTA 标讯 — ${tenders.length} 条新*\n\n${lines}\n\n📊 [Intel Dashboard](https://freightracing.ca/intel) · _WF5_`;
return [{ json: { message: msg } }];
